export function getLevel(id: number): Level | undefined {
  return LEVELS[id];
}

export function getLevelsByIsland(start: number, end: number): Level[] {
  return Array.from({ length: end - start + 1 }, (_, i) => LEVELS[start + i]).filter(Boolean) as Level[];
}

export function isBossLevel(id: number): boolean {
  return LEVELS[id]?.isBoss === true;
}

export const TOTAL_LEVELS = 270;
